var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"우선, 실행위원장으로서 내일 학원제의 준비 상황을 보고하자면……","JPN":"さて、まずは学園祭実行委員長の俺から\\n明日に控えた学園祭の進捗状況を報告する。","ENG":"First and foremost, as the head of the executive committee, I'll report on the status of preparations for tomorrow's festival...","TWN":"首先，就由身為執行委員長的我，來跟大家報告學園祭的準備情形……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전체적으로는 순조로운 편이지만, 현재 몇몇 동아리로부터 클레임이 접수된 상태야.","JPN":"全体的には順調だが、\\nいくつか苦情やトラブルの報告が寄せられている。","ENG":"Everything is going smoothly overall, but a few clubs have filed some complaints.","TWN":"整體而言是順利的，只是有幾個社團提出一些訴求。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 임원들이 각각 분담해서 해결하면 좋겠네요.","JPN":"なるほど。\\n役員で各トラブルを分担して解決を図りましょうか。","ENG":"I see. The members can each take charge of one and resolve the issues.","TWN":"是嗎？那就由幹部們一起分頭處理吧。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 보나마나 쓰잘 데 없는 요청이겠지.","JPN":"ふん、どうせくだらない文句ばかりでしょう。","ENG":"Hmph. I bet it's just another stupid request.","TWN":"哼，想也知道是無理的要求。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양. 그러지말고 이야기를 들어봐요.","JPN":"ナイエルさん、まずは話を聞かないと。","ENG":"Naielle, please try to listen to them at least.","TWN":"奈爾，你別這樣，先把話聽完。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래서? 무슨 클레임인데?","JPN":"それで？　どんな苦情が来ているの？","ENG":"So? What are their complaints?","TWN":"所以呢？是什麼樣的訴求？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"먼저 수영부에서 클레임을 보내왔어.","JPN":"まずは、水泳部からの苦情だな。","ENG":"First, from the swim club.","TWN":"首先是游泳部的訴求。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"수영부에서는 카페를 준비하고 있는데, 카페 주변에서 원인 모를 악취가 난다고 해.","JPN":"水泳部はカフェを準備しているが、どこからか原因不明の悪臭がしているそうだ。","ENG":"They are preparing to open a cafe, but they keep smelling this awful odor nearby.","TWN":"他們表示，游泳部在籌備開設咖啡廳，但咖啡廳周圍卻發出不明惡臭。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이대로는 카페 운영이 어렵다면서 학생회에게 도움을 요청했어.","JPN":"このままではカフェを運営するにあたって支障が出てしまう。","ENG":"They are asking us for help as they claim it will be difficult to run a cafe with the awful smell in the air.","TWN":"這樣會導致咖啡廳經營上的困難，因此希望學生會介入幫忙。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야 뭘 그런 걸 가지고! 애초에 본인들이 수영장 청소를 똑바로 안 했겠지!","JPN":"何よ、その程度のことで！\\nそもそも本人たちがプールの掃除をきちんとしなかったせいでしょ？","ENG":"That's it?! My guess is that they didn't scrub the pool hard enough!","TWN":"他們還真敢說！肯定是他們自己沒有把游泳池打掃乾淨吧！"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야, 나이엘. 우리가 얼마나 수영장 관리를 열심히 하는데?","JPN":"なに言ってるの、ナイエル。\\n普段、私たちはちゃんと管理してるんだから。","ENG":"That's not true, Naielle. We take pool maintenance very seriously!","TWN":"你少胡說，奈爾。我們可是很認真在管理游泳池的！"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"애초에 우리 학생들이 다 같이 쓰는 수영장이잖아, 청소도 매일같이 하고 있고.","JPN":"なんてたって、自分たちで使うプールだからね。\\n掃除だって毎日きちんとしてるよ。","ENG":"It's for everyone to use, so we clean it daily.","TWN":"而且游泳池不是大家一起共用的嗎？我們每天都有打掃。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"흠. 그러고보니 셜리 넌 수영부랑 학생회를 겸임하고 있었지? ","JPN":"ふむ。シャーリーは水泳部と生徒会を兼任していたな。","ENG":"Hmm. Shirley, you're also a member of the swim club, right? ","TWN":"嗯，這麼說來，夏麗，游泳部和學生會你都有加入吧？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그럼 그쪽 사정을 잘 알겠네. 수영부 건을 부탁해도 될까?","JPN":"なら、そちらの事情には詳しいはずだ。\\n水泳部の件はシャーリーに頼んでもいいか？","ENG":"Then you'll know their situation better than any of us. Can you take care of this one?","TWN":"那你應該很清楚情況，游泳部的事可以交給你嗎？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응, 알았어! 나한테 맡겨!","JPN":"うん、わかった！　私に任せて！","ENG":"Okay! Leave it to me!","TWN":"嗯，沒問題！我來處理！"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"다음은 사진부에서 온 건이야. 전시에 관해 문제가 있다고 하는군.","JPN":"次は写真部からだ。展示に関してのトラブルだな","ENG":"Next is from the photography club. They seem to be having a problem regarding their exhibition.","TWN":"接下來是攝影部的訴求，是與展出有關的問題。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시 일정을 다시 조율해달라고 하는데…… 아마, 이쪽은 문제가 좀 복잡할 지도 몰라.","JPN":"展示日程を再度調整してほしいとのことだが……\\nおそらくこちらは解決には、やや手こずるだろう。","ENG":"They want us to reschedule the exhibition, but... I think it'll be more complicated than that.","TWN":"他們希望可以調整展出的日期……這個問題可能會有點複雜。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응? 어째서?","JPN":"うん？　どうして？","ENG":"Hmm? How so?","TWN":"嗯？為什麼？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진부와 미술부는 학원제 때마다 전시관을 공유하거든. 그래서 서로 트러블이 잦아.","JPN":"写真部と美術部は学園祭の時、毎回展示会場を共有する。\\nそのためトラブルが起きることが多いんだ。","ENG":"The photography club and art club have shared the gallery every festival. So those two are always bickering with each other.","TWN":"攝影部和美術部每次在學園祭時都會共用展覽館，彼此常常發生衝突。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 전시 공간은 한정되어 있어. 학생회에서도 모든 요구를 들어줄 수는 없고.","JPN":"しかし、展示スペースは限られている。\\n生徒会とはいえ、すべての要求を聞き入れることは出来ない。","ENG":"However, the gallery space is limited, and we can't say yes to every request.","TWN":"不過展示空間就那麼大，學生會也不可能滿足所有的要求。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 그깟 아마추어 전시를 누가 본다고! 그냥 무시해버려!","JPN":"ふん！　あんなアマチュアの展示に需要あんの？　無視しちゃえば？","ENG":"Hmph! Who cares about an exhibition by amateurs? Just ignore them!","TWN":"哼！那種業餘的展覽誰要看！不用理他們啦！"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래도 한 해 동안의 결과물을 전시하는 자리잖아? 되도록이면 둘 다 좋은 조건으로 전시하고 싶겠지.","JPN":"でも一年間の成果を披露する場じゃない？\\nどちらも出来るだけ良い展示にしたいだろうしね。","ENG":"But they've been working on it all year, right? I get why they both want a good deal.","TWN":"但那是他們辛苦一年的成果，當然會想在好的環境下展出吧？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"옳은 말이야, 카렌.","JPN":"そのとおりだ、カレン。","ENG":"Exactly, Kallen.","TWN":"你說的沒錯，卡蓮。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};